    "content": "{"content":"// SPDX-License-Identifier: GPL-2.0\n/*\n * Data Access Monitor\n *\n * Author: SeongJae Park <sj@kernel.org>\n */\n\n#define pr_fmt(fmt) \"damon: \" fmt\n\n#include <linux/damon.h>\n#include <linux/delay.h>\n#include <linux/kthread.h>\n#include <linux/memcontrol.h>\n#include <linux/mm.h>\n#include <linux/psi.h>\n#include <linux/slab.h>\n#include <linux/string.h>\n#include <linux/string_choices.h>\n\n#define CREATE_TRACE_POINTS\n#include <trace/events/damon.h>\n\nstatic DEFINE_MUTEX(damon_lock);\nstatic int nr_running_ctxs;\nstatic bool running_exclusive_ctxs;\n\nstatic DEFINE_MUTEX(damon_ops_lock);\nstatic struct damon_operations damon_registered_ops[NR_DAMON_OPS];\n\nstatic struct kmem_cache *damon_region_cache __ro_after_init;\n\n/* Should be called under damon_ops_lock with id smaller than NR_DAMON_OPS */\nstatic bool __damon_is_registered_ops(enum damon_ops_id id)\n{\n\tstruct damon_operations empty_ops = {};\n\n\tif (!memcmp(&empty_ops, &damon_registered_ops[id], sizeof(empty_ops)))\n\t\treturn false;\n\treturn true;\n}\n\n/**\n * damon_is_registered_ops() - Check if a given damon_operations is registered.\n * @id:\tId of the damon_operations to check if registered.\n *\n * Return: true if the ops is set, false otherwise.\n */\nbool damon_is_registered_ops(enum damon_ops_id id)\n{\n\tbool registered;\n\n\tif (id >= NR_DAMON_OPS)\n\t\treturn false;\n\tmutex_lock(&damon_ops_lock);\n\tregistered = __damon_is_registered_ops(id);\n\tmutex_unlock(&damon_ops_lock);\n\treturn registered;\n}\n\n/**\n * damon_register_ops() - Register a monitoring operations set to DAMON.\n * @ops:\tmonitoring operations set to register.\n *\n * This function registers a monitoring operations set of valid &struct\n * damon_operations->id so that others can find and use them later.\n *\n * Return: 0 on success, negative error code otherwise.\n */\nint damon_register_ops(struct damon_operations *ops)\n{\n\tint err = 0;\n\n\tif (ops->id >= NR_DAMON_OPS)\n\t\treturn -EINVAL;\n\n\tmutex_lock(&damon_ops_lock);\n\t/* Fail for already registered ops */\n\tif (__damon_is_registered_ops(ops->id))\n\t\terr = -EINVAL;\n\telse\n\t\tdamon_registered_ops[ops->id] = *ops;\n\tmutex_unlock(&damon_ops_lock);\n\treturn err;\n}\n\n/**\n * damon_select_ops() - Select a monitoring operations to use with the context.\n * @ctx:\tmonitoring context to use the operations.\n * @id:\t\tid of the registered monitoring operations to select.\n *\n * This function finds registered monitoring operations set of @id and make\n * @ctx to use it.\n *\n * Return: 0 on success, negative error code otherwise.\n */\nint damon_select_ops(struct damon_ctx *ctx, enum damon_ops_id id)\n{\n\tint err = 0;\n\n\tif (id >= NR_DAMON_OPS)\n\t\treturn -EINVAL;\n\n\tmutex_lock(&damon_ops_lock);\n\tif (!__damon_is_registered_ops(id))\n\t\terr = -EINVAL;\n\telse\n\t\tctx->ops = damon_registered_ops[id];\n\tmutex_unlock(&damon_ops_lock);\n\treturn err;\n}\n\n#ifdef CONFIG_DAMON_DEBUG_SANITY\nstatic void damon_verify_new_region(unsigned long start, unsigned long end)\n{\n\tWARN_ONCE(start >= end, \"start %lu >= end %lu\\n\", start, end);\n}\n#else\nstatic void damon_verify_new_region(unsigned long start, unsigned long end)\n{\n}\n#endif\n\n/*\n * Construct a damon_region struct\n *\n * Returns the pointer to the new struct if success, or NULL otherwise\n */\nstruct damon_region *damon_new_region(unsigned long start, unsigned long end)\n{\n\tstruct damon_region *region;\n\n\tdamon_verify_new_region(start, end);\n\tregion = kmem_cache_alloc(damon_region_cache, GFP_KERNEL);\n\tif (!region)\n\t\treturn NULL;\n\n\tregion->ar.start = start;\n\tregion->ar.end = end;\n\tregion->nr_accesses = 0;\n\tregion->nr_accesses_bp = 0;\n\tINIT_LIST_HEAD(&region->list);\n\n\tregion->age = 0;\n\tregion->last_nr_accesses = 0;\n\n\treturn region;\n}\n\nvoid damon_add_region(struct damon_region *r, struct damon_target *t)\n{\n\tlist_add_tail(&r->list, &t->regions_list);\n\tt->nr_regions++;\n}\n\n#ifdef CONFIG_DAMON_DEBUG_SANITY\nstatic void damon_verify_del_region(struct damon_target *t)\n{\n\tWARN_ONCE(t->nr_regions == 0, \"t->nr_regions == 0\\n\");\n}\n#else\nstatic void damon_verify_del_region(struct damon_target *t)\n{\n}\n#endif\n\nstatic void damon_del_region(struct damon_region *r, struct damon_target *t)\n{\n\tdamon_verify_del_region(t);\n\n\tlist_del(&r->list);\n\tt->nr_regions--;\n}\n\nstatic void damon_free_region(struct damon_region *r)\n{\n\tkmem_cache_free(damon_region_cache, r);\n}\n\nvoid damon_destroy_region(struct damon_region *r, struct damon_target *t)\n{\n\tdamon_del_region(r, t);\n\tdamon_free_region(r);\n}\n\nstatic bool damon_is_last_region(struct damon_region *r,\n\t\tstruct damon_target *t)\n{\n\treturn list_is_last(&r->list, &t->regions_list);\n}\n\n/*\n * Check whether a region is intersecting an address range\n *\n * Returns true if it is.\n */\nstatic bool damon_intersect(struct damon_region *r,\n\t\tstruct damon_addr_range *re)\n{\n\treturn !(r->ar.end <= re->start || re->end <= r->ar.start);\n}\n\n/*\n * Fill holes in regions with new regions.\n */\nstatic int damon_fill_regions_holes(struct damon_region *first,\n\t\tstruct damon_region *last, struct damon_target *t)\n{\n\tstruct damon_region *r = first;\n\n\tdamon_for_each_region_from(r, t) {\n\t\tstruct damon_region *next, *newr;\n\n\t\tif (r == last)\n\t\t\tbreak;\n\t\tnext = damon_next_region(r);\n\t\tif (r->ar.end != next->ar.start) {\n\t\t\tnewr = damon_new_region(r->ar.end, next->ar.start);\n\t\t\tif (!newr)\n\t\t\t\treturn -ENOMEM;\n\t\t\tdamon_insert_region(newr, r, next, t);\n\t\t}\n\t}\n\treturn 0;\n}\n\n/*\n * damon_set_regions() - Set regions of a target for given address ranges.\n * @t:\t\tthe given target.\n * @ranges:\tarray of new monitoring target ranges.\n * @nr_ranges:\tlength of @ranges.\n * @min_region_sz:\tminimum region size.\n *\n * This function adds new regions to, or modify existing regions of a\n * monitoring target to fit in specific ranges.\n *\n * R